member.example:
Bind a named Smart String variable on a LocalizeStringEvent to a ViewModel value using a serialized binder field — the target LocalizeStringEvent and variable name are assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private LocalizeStringEventVariableBinder _score;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public int _score; // updates the named Smart String variable
    }


Bind a named Smart String variable on a LocalizeStringEvent to a ViewModel value by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private LocalizeStringEvent _target;
        
        private LocalizeStringEventVariableBinder Score =>
            new(_target, variableName: "score");
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public int _score;
    }
